// Linear search on a 10-element array.
// Same algorithm — three completely different outcomes.

function linearSearch(arr, target) {
  let comparisons = 0;
  for (let i = 0; i < arr.length; i++) {
    comparisons++;
    if (arr[i] === target) return { found: i, comparisons };
  }
  return { found: -1, comparisons };
}

const arr = [4, 7, 2, 9, 1, 5, 8, 3, 6, 10];

// BEST CASE — target is at index 0
console.log('best:   ', linearSearch(arr, 4));

// WORST CASE — target is at the end OR not present
console.log('worst:  ', linearSearch(arr, 10));
console.log('missing:', linearSearch(arr, 99));

// AVERAGE — assume target is equally likely to be anywhere
// Expected comparisons ≈ n/2 for a present target, n for missing.

