// Amortized analysis in action.
// arr.push() resizes the internal buffer occasionally.
// Most pushes are O(1). When the buffer doubles, that one push is O(n).
// Over many pushes, the total cost is O(n) — averaging O(1) per push.

function timeManyPushes(n) {
  const arr = [];
  const t0 = performance.now();
  for (let i = 0; i < n; i++) arr.push(i);
  const t1 = performance.now();
  return t1 - t0;
}

console.log('1,000   pushes:', timeManyPushes(1000).toFixed(2),     'ms');
console.log('10,000  pushes:', timeManyPushes(10000).toFixed(2),    'ms');
console.log('100,000 pushes:', timeManyPushes(100000).toFixed(2),   'ms');
console.log('1,000,000 pushes:', timeManyPushes(1000000).toFixed(2),'ms');

// Each line is roughly 10× the previous — linear in n total,
// constant per push (amortized).
